function initHeroYoutube(){const i=document.querySelectorAll("[data-hero-youtube]");if(!i.length)return;const s=window.matchMedia("(min-width: 768px)").matches,u=window.matchMedia("(prefers-reduced-motion: reduce)").matches;i.forEach(e=>{const o=e.dataset.videoId?.trim(),n=e.querySelector(".main-hero__video");if(!o||!n||!s||u){e.classList.add("is-no-video");return}if(e.classList.remove("is-no-video"),e.dataset.youtubeInitialized==="true")return;e.dataset.youtubeInitialized="true";let a=!1;const c=()=>{a||(a=!0,e.classList.add("is-video-loaded"))},d=()=>{new YT.Player(n,{videoId:o,playerVars:{autoplay:1,controls:0,disablekb:1,fs:0,modestbranding:1,loop:1,playlist:o,rel:0,mute:1,playsinline:1},events:{onReady:function(t){t.target.mute(),t.target.playVideo()},onStateChange:function(t){t.data===YT.PlayerState.PLAYING&&c()}}})};if(window.YT&&window.YT.Player){d();return}if(!document.querySelector('script[src="https://www.youtube.com/iframe_api"]')){const t=document.createElement("script");t.src="https://www.youtube.com/iframe_api",document.head.appendChild(t)}const r=window.onYouTubeIframeAPIReady;window.onYouTubeIframeAPIReady=function(){typeof r=="function"&&r(),d()}})}document.readyState==="loading"?document.addEventListener("DOMContentLoaded",initHeroYoutube):initHeroYoutube();
